  "questionProse": [
    "किसी एल्गोरिदम की टाइम कॉम्प्लेक्सिटी क्या है जो इनपुट के आकार की परवाह किए बिना हमेशा समान समय लेता है?"
  ],
  "explanationProse": [
    "O(1) स्थिर समय जटिलता को दर्शाता है। इसका मतलब है कि एल्गोरिदम इनपुट के आकार की परवाह किए बिना हमेशा समान समय लेता है।"
  ]
}
